export const crisisReply = () => {
  const replies = [
    "I’m really glad you spoke up 💙 What you’re feeling is heavy, but you are NOT alone. This pain is temporary — your life is important.",
    
    "I hear you 😔 Please pause with me for a moment. You matter more than you realize, and help is already being reached out for you.",

    "I know it feels unbearable right now 💔 But this moment does not define your future. Someone cares deeply about you — and support is on the way.",

    "Thank you for telling me 💙 You don’t have to fight this alone. Let’s slow down together and breathe."
  ];

  return replies[Math.floor(Math.random() * replies.length)];
};
